#include <stdio.h>
#include <inttypes.h>
int main(){
    int T; if(scanf("%d", &T)!=1) return 0;
    while(T--){
        int64_t X, Y; scanf("%" PRId64 " %" PRId64, &X, &Y);
        int64_t K = Y / (X - 1);
        printf("%" PRId64 "\n", K);
    }
    return 0;
}

